package com.mailautomation.service;
import com.mailautomation.domain.EmailModels.*;import org.springframework.beans.factory.annotation.Value;import org.springframework.stereotype.Service;import java.util.*;
@Service public class EscalationService { @Value("${app.ai.confidence-threshold:0.70}") double threshold; public List<String> reasons(Email email){ List<String> r=new ArrayList<>(); if(email.category==Category.LEGAL) r.add("Legal category detected"); if(email.sentiment==Sentiment.ANGRY&&email.priorAngryInteractions>=2) r.add("Third angry interaction"); if(email.vipCustomer) r.add("VIP customer"); if(email.confidenceScore<threshold) r.add("AI confidence below threshold"); if(email.content!=null&&email.content.toLowerCase().contains("attached legal")) r.add("Sensitive attachment review"); return r; }}
